	public ObjectConstructionException EnrichWithInformationAbout<TObjectUnderConstruction, T1, T2, T3, T4>(IEnumerable<object?> constructionMethodParameters, [CallerMemberName] string callerMethodName = "")
	=> AddInformationAboutContextHigherThanSourceFailure<TObjectUnderConstruction>(constructionMethodParameters, methodGenericTypeParameters: new[] { typeof(T1), typeof(T2), typeof(T3), typeof(T4) }, callerMethodName);
	ObjectConstructionException AddInformationAboutContextHigherThanSourceFailure<TObjectUnderConstruction>(
		IEnumerable<object?> constructionMethodParameters,
		IEnumerable<Type> methodGenericTypeParameters,
		string callerMethodName)
	{
		_objectConstructionLayers.Push(
			typeof(TObjectUnderConstruction),
			BuildMessageAboutInstanceConstructionFailure(
				typeof(TObjectUnderConstruction).Name,
				typeof(TObjectUnderConstruction).Namespace!,
				innerException: null,
				ruleThatInvalidatesTheInstanceConstruction: null,
				callerMethodName,
				constructionMethodParameters.ToArray(),
				methodGenericTypeParameters.ToArray()));
		return this;
	}

	static string BuildMessageAboutInstanceConstructionFailure(
		string objectUnderConstruction,
		string objectUnderConstructionNamespace,
		Exception? innerException,
		string? ruleThatInvalidatesTheInstanceConstruction,
		string callerMethodName,
		IReadOnlyCollection<object?> constructionMethodParameters,
		IEnumerable<Type> methodGenericTypeParameters)
	{
		var sb = new StringBuilder();

		sb.Append($"{objectUnderConstruction}: construction failed ");

		if (innerException != null)
		{
			sb.Append($"due to {innerException.GetType().Name} ");
		}

		if (!string.IsNullOrEmpty(ruleThatInvalidatesTheInstanceConstruction))
		{
			sb.Append($"({ruleThatInvalidatesTheInstanceConstruction}) ");
		}

		sb.Append($"via {BuildCallerMethodSignatureApproximation(objectUnderConstruction, callerMethodName, constructionMethodParameters, methodGenericTypeParameters)} ");

		if (constructionMethodParameters.Count == 1)
		{
			sb.Append($"with the following parameter: {constructionMethodParameters.First().GetStringRepresentation()} ");
		}
		else if (constructionMethodParameters.Count > 1)
		{
			sb.Append($"with the following parameters: [{string.Join(", ", constructionMethodParameters.Select(p => p.GetStringRepresentation()))}] ");
		}

		if (!string.IsNullOrEmpty(objectUnderConstructionNamespace))
		{
			sb.Append($"[{objectUnderConstructionNamespace}]");
		}

		return sb.ToString();
	}

	static string BuildMessageAboutSpecificMemberConstructionFailure(
		string objectUnderConstruction,
		string objectUnderConstructionNamespace,
		Type? objectBuilderType,
		string memberUnderConstruction,
		object? invalidValue,
		Exception? innerException,
		string? ruleThatInvalidatesTheValue,
		IEnumerable<object?> constructionMethodParameters,
		IEnumerable<Type> methodGenericTypeParameters,
		string callerMethodName)
	{
		var sb = new StringBuilder();

		sb.Append($"{objectUnderConstruction}: ");

		if (!string.IsNullOrEmpty(callerMethodName) && !callerMethodName.Contains(".ctor"))
		{
			sb.Append("when called from ");
			if (objectBuilderType != null)
			{
				sb.Append(objectBuilderType.Name);
				if (!String.IsNullOrEmpty(objectBuilderType.FullName))
				{
					sb.Append($"[{objectBuilderType.Namespace}]");
				}
				sb.Append('.');
			}
			sb.Append($"{BuildCallerMethodSignatureApproximation(objectUnderConstruction, callerMethodName, constructionMethodParameters, methodGenericTypeParameters)}, ");
		}

		sb.Append($"{memberUnderConstruction} cannot accept value {invalidValue.GetStringRepresentation()}");

		if (innerException != null)
		{
			sb.Append($" due to {innerException.GetType().Name}");
		}

		if (!string.IsNullOrEmpty(ruleThatInvalidatesTheValue))
		{
			sb.Append($": {Format(ruleThatInvalidatesTheValue, objectUnderConstruction, memberUnderConstruction)}");
		}

		if (!string.IsNullOrEmpty(objectUnderConstructionNamespace))
		{
			sb.Append($" [{objectUnderConstructionNamespace}]");
		}

		return sb.ToString();
	}

	static string? Format(string? rule, string objectUnderConstruction, string memberUnderConstruction)
	=> rule switch
	{
		null => null,
		_ => rule
			.Replace("@type", objectUnderConstruction)
			.Replace("@member", memberUnderConstruction)
	};

	static string BuildCallerMethodSignatureApproximation(
		string objectUnderConstruction,
		string callerMethodName,
		IEnumerable<object?> constructionMethodParameters,
		IEnumerable<Type> methodGenericTypeParameters)
	{
		var methodSignature = new StringBuilder();
		methodSignature.Append($"{objectUnderConstruction}.{callerMethodName}");
		if (methodGenericTypeParameters.Any())
		{
			methodSignature.Append($"<{string.Join(',', methodGenericTypeParameters.Select(p => p.Name))}>");
		}
		methodSignature.Append($"({string.Join(", ", constructionMethodParameters.Select(p => p?.GetType().Name ?? "_"))})");
		return methodSignature.ToString();
	}
}
